<script setup lang="ts">
import { onMounted, ref } from 'vue'
import NewCustomer from './NewCustomer.vue'
import { useI18n } from 'vue-i18n'
import { getAllContacts, deleteContact, archiveContact } from '../../../core/requests/Contacts'
import { useToast } from 'vuestic-ui'
import EditCustomer from './EditCustomer.vue'
import { format } from 'date-fns'
import NewOportunity from '../../oportunities/pages/NewOportunity.vue'
import NewCompany from './NewCompany.vue'

const { notify } = useToast()

const items = ref([])
const showNewCustomer = ref(false)
const showNewCompany = ref(false)
const showViewCustomer = ref(false)
const showConfirm = ref(false)
const contactSelected: any = ref(null)
const isDeleting = ref(false)
const isLoading = ref(false)
const showNewOportunity = ref(false)
const filteredCount = ref(0)
const perPage = ref(12)
const currentPage = ref(1)
const inputSearch = ref('')
const { t } = useI18n()
const columns = [
  { key: 'id', sortable: false },
  { key: 'Nombres Completos', sortable: false },
  { key: 'Empresa', sortable: false },
  { key: 'Documento', sortable: false },
  { key: 'Teléfono', sortable: false },
  { key: 'Correo', sortable: false },
  { key: 'Fecha Creación', sortable: false },
  { key: 'Acciones', width: 80, sortable: false },
]

onMounted(() => {
  getContacts()
})

const getContacts = async (params?: any) => {
  isLoading.value = true
  const contacts: any = await getAllContacts(params)
  items.value = contacts.map((i: any) => ({
    ...i,
    'Nombres Completos': i.fullname,
    Empresa: i.company?.ruc,
    Documento: i.document,
    Teléfono: i.cellphone,
    Correo: i.email,
    'Fecha Creación': format(i.created_at, 'dd/MM/yyyy hh:mm aa'),
    Acciones: true,
    activeTab: 0,
  }))
  isLoading.value = false
}
const viewDetail = (id: any) => {
  showViewCustomer.value = id ? true : false
  contactSelected.value = id
}
// const viewQuotation = (id: any) => {
//   showNewOportunity.value = true
// }
const needConfirm = (id: any) => {
  showConfirm.value = id ? true : false
  contactSelected.value = id
}
const onClosed = () => {
  showNewCustomer.value = false
  showViewCustomer.value = false
  getContacts()
}
const doDelete = async () => {
  isDeleting.value = true
  await deleteContact(contactSelected.value)
  notify({
    message: 'Cliente eliminado correctamente',
    color: 'success',
    duration: 1000,
  })
  setTimeout(() => {
    isDeleting.value = false
    needConfirm(null)
    getContacts()
  })
}

const pages = () => {
  return perPage.value && perPage.value !== 0 ? Math.ceil(items.value.length / perPage.value) : items.value.length
}

// const doFilterByRange = () => {
//   const { start, end } = startDate.value
//   if (start && end) {
//     const fromDate = new Date(start).setHours(24)
//     const toDate = new Date(end).setHours(24)

//     getContacts({
//       start: new Date(fromDate).getTime(),
//       end: new Date(toDate).getTime(),
//     })
//   }
// }
const download = () => {
  console.log('download')
}
const isProcessing = ref(false)
const showConfirmArchive = ref(false)
const needConfirmArchive = (id: any) => {
  showConfirmArchive.value = id ? true : false
  contactSelected.value = id
}
const doArchive = async () => {
  await archiveContact(contactSelected.value)
  items.value = items.value.filter((f: any) => f.id !== contactSelected.value)
  contactSelected.value = null
  showConfirmArchive.value = false
  notify({
    message: 'Cliente archivado correctamente',
    color: 'success',
    duration: 1000,
  })
}
</script>

<template>
  <div class="py-4">
    <div class="flex justify-between align-center justify-center">
      <h1 class="h5 m-0">{{ t('contacts.allContacts') }} ({{ items.length }})</h1>
      <div class="flex gap-2">
        <VaButton icon="exit_to_app" color="info" @click="download">
          <span class="px-1">Descargar</span>
        </VaButton>

        <VaButton icon="domain_add" color="primary" @click="showNewCompany = true">
          <span class="px-1">{{ t('contacts.newCompany') }}</span>
        </VaButton>

        <VaButton icon="person_add" color="primary" @click="showNewCustomer = true">
          <span class="px-1">{{ t('contacts.newContact') }}</span>
        </VaButton>
      </div>
    </div>
    <div class="mt-5">
      <div class="columns-5 mb-7">
        <div>
          <VaInput
            v-model="inputSearch"
            :label="t('contacts.search')"
            placeholder="Escribe lo que buscas"
            class="text-xxs"
            clearable
            background="#fff"
          />
        </div>
      </div>

      <div class="w-full bg-white p-2">
        <VaDataTable
          :items="items"
          :columns="columns"
          class="text-xs"
          hoverable
          selected-color="#eee"
          :filter="inputSearch"
          :per-page="perPage"
          :current-page="currentPage"
          :loading="isLoading"
          :no-data-html="'...'"
          @filtered="filteredCount = $event.items.length"
        >
          <template #cell(Acciones)="{ row, isExpanded }">
            <div class="flex gap-1">
              <VaButton icon="archive" color="gray" round @click="needConfirmArchive(row?.rowData?.id)"></VaButton>
              <!-- <VaButton icon="note_add" color="#a650de" round @click="viewQuotation(row?.rowData?.id)"></VaButton> -->
              <VaButton icon="edit" color="#158de3" round @click="viewDetail(row?.rowData?.id)"></VaButton>
              <VaButton
                :icon="isExpanded ? 'va-arrow-up' : 'va-arrow-down'"
                preset="primary"
                @click="row.toggleRowDetails()"
              >
              </VaButton>
            </div>
          </template>

          <template #cell(Empresa)="{ row }">
            <span class="font-bold text-primary">{{ row.rowData?.company?.ruc }}</span>
          </template>

          <template #bodyAppend>
            <tr>
              <td colspan="8">
                <div class="flex justify-end mt-4">
                  <VaPagination
                    v-model="currentPage"
                    size="small"
                    class="text-xs mb-3 justify-center sm:justify-start"
                    buttons-preset="primary"
                    active-page-color="textPrimary"
                    :pages="pages()"
                  />
                </div>
              </td>
            </tr>
          </template>

          <template #expandableRow="{ rowData }">
            <div class="flex px-2 py-3 gap-2 bg-blue-50 mx-10 rounded my-2">
              <div class="w-full pl-2">
                <div class="gap-1">
                  <span class="text-base font-medium">
                    <span class="uppercase font-black">{{ rowData['Nombres Completos'] }}</span>
                  </span>
                </div>
                <div class="w-full columns-6 mt-2 mb-1">
                  <div v-if="rowData.Documento" class="w-full items-center text-xs">
                    <b>DNI:</b> <br />
                    <span>
                      {{ rowData.Documento }}
                      <VaIcon size="10px" class="cursor-pointer" name="content_copy" />
                    </span>
                  </div>
                  <div v-if="rowData.ruc" class="w-full items-center text-xs">
                    <b>RUC:</b> <br />
                    <span>
                      {{ rowData.ruc }}
                      <VaIcon size="10px" class="cursor-pointer" name="content_copy" />
                    </span>
                  </div>
                  <div v-if="rowData.cellphone" class="w-full items-center text-xs">
                    <b>Teléfono:</b> <br />
                    <span>
                      {{ rowData.cellphone }}
                      <VaIcon size="10px" class="cursor-pointer" name="content_copy" />
                    </span>
                  </div>
                  <div v-if="rowData.whatsapp" class="w-full items-center text-xs">
                    <b>WhatsApp:</b> <br />
                    <span>
                      {{ rowData.whatsapp }}
                      <VaIcon size="10px" class="cursor-pointer" name="content_copy" />
                    </span>
                  </div>
                  <div v-if="rowData.email" class="w-full items-center text-xs">
                    <b>Correo Electrónico:</b> <br />
                    <span>
                      {{ rowData.email }}
                      <VaIcon size="10px" class="cursor-pointer" name="content_copy" />
                    </span>
                  </div>
                </div>

                <div class="flex flex-col bg-white mt-6 py-2 pb-5 px-4">
                  <VaTabs v-model="rowData.activeTab">
                    <template #tabs>
                      <VaTab v-for="tab in ['Empresa']" :key="tab">
                        {{ tab }}
                      </VaTab>
                    </template>
                  </VaTabs>

                  <div v-if="rowData.activeTab === 1" class="bg-gray-100 p-3 rounded mt-4 pb-5">
                    <p v-if="!rowData.quotations?.length" class="bg-red-300 font-bold p-2 -mb-1">
                      El cliente no tiene cotizaciones
                    </p>

                    <div v-if="rowData.quotations?.length" class="va-table-responsive w-full">
                      <table class="va-table w-full">
                        <thead>
                          <tr>
                            <th>n° Cotización</th>
                            <th>Comercial</th>
                            <th>Servicios</th>
                            <th>Vehiculos</th>
                            <th>Fecha Creación</th>
                            <th>Estado</th>
                          </tr>
                        </thead>
                        <tbody>
                          <tr v-for="user in rowData.quotations" :key="user.id">
                            <td>{{ user.fullName }}</td>
                            <td>{{ user.fullName }}</td>
                            <td>{{ user.fullName }}</td>
                            <td>{{ user.fullName }}</td>
                            <td>{{ user.fullName }}</td>
                            <td>{{ user.fullName }}</td>
                          </tr>
                        </tbody>
                      </table>
                    </div>
                  </div>

                  <div v-if="rowData.activeTab === 2" class="bg-gray-100 p-3 rounded mt-4 pb-5">
                    <p class="bg-red-300 font-bold p-2">El cliente no tiene ordenes de trabajo</p>

                    <div class="va-table-responsive w-full">
                      <table class="va-table w-full">
                        <thead>
                          <tr>
                            <th>n° Orden</th>
                            <th>Responsable</th>
                            <th>Servicios</th>
                            <th>Vehiculos</th>
                            <th>Fecha Inicio</th>
                            <th>Fecha Fin</th>
                          </tr>
                        </thead>
                        <tbody>
                          <!-- <tr v-for="user in []" :key="user.id">
                            <td>{{ user.fullName }}</td>
                            <td>{{ user.fullName }}</td>
                            <td>{{ user.fullName }}</td>
                            <td>{{ user.fullName }}</td>
                            <td>{{ user.fullName }}</td>
                          </tr> -->
                        </tbody>
                      </table>
                    </div>
                  </div>

                  <div v-if="rowData.activeTab === 0" class="bg-gray-100 p-3 rounded mt-4 pb-5">
                    <p v-if="!rowData.company" class="bg-red-300 font-bold p-2 -mb-1">
                      El cliente no está asociado a empresa
                    </p>

                    <div v-if="rowData.company" class="va-table-responsive w-full">
                      <table class="va-table w-full">
                        <thead>
                          <tr>
                            <th>Razón Social</th>
                            <th>RUC</th>
                            <th>Teléfono</th>
                            <th>WhatsApp</th>
                            <th>Fecha Creación</th>
                          </tr>
                        </thead>
                        <tbody>
                          <tr>
                            <td>{{ rowData.company?.socialreason }}</td>
                            <td>{{ rowData.company?.ruc }}</td>
                            <td>{{ rowData.company?.phone }}</td>
                            <td>{{ rowData.company?.whatsapp }}</td>
                            <td>{{ rowData.company?.created_at }}</td>
                          </tr>
                        </tbody>
                      </table>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </template>
        </VaDataTable>

        <VaAlert v-if="false" class="!mt-6 py-1 text-xs" color="info">
          Cantidad de resultados:
          <VaChip class="text-xs font-bold ml-1 px-0" color="#fff">{{ filteredCount }}</VaChip>
        </VaAlert>
      </div>
    </div>

    <VaModal v-model="showNewCompany" hide-default-actions size="340px" close-button blur no-dismiss>
      <div>
        <NewCompany @close="showNewCompany = false" />
      </div>
    </VaModal>

    <VaModal v-model="showNewCustomer" hide-default-actions size="medium" close-button blur no-dismiss>
      <div class="mt-4">
        <NewCustomer @close="onClosed" />
      </div>
    </VaModal>

    <VaModal v-model="showConfirmArchive" size="250px" hide-default-actions no-dismiss blur>
      <p class="text-sm">¿Deseas archivar este cliente?</p>

      <template #footer>
        <VaButton size="small" preset="secondary" class="mr-1" @click="needConfirmArchive(null)"> Cancelar</VaButton>
        <VaButton size="small" :loading="isProcessing" @click="doArchive"> Continuar</VaButton>
      </template>
    </VaModal>

    <VaModal v-model="showViewCustomer" hide-default-actions size="medium" close-button blur no-dismiss>
      <div class="mt-4">
        <EditCustomer :id="contactSelected" @close="onClosed" />
      </div>
    </VaModal>

    <VaModal v-model="showNewOportunity" hide-default-actions size="medium" close-button blur no-dismiss>
      <div class="mt-4">
        <NewOportunity />
      </div>
    </VaModal>

    <VaModal v-model="showConfirm" size="250px" hide-default-actions no-dismiss blur>
      <p class="text-sm">¿Deseas eliminar este cliente?</p>

      <template #footer>
        <VaButton size="small" preset="secondary" class="mr-1" @click="needConfirm(null)"> Cancelar</VaButton>
        <VaButton size="small" :loading="isDeleting" @click="doDelete"> Continuar</VaButton>
      </template>
    </VaModal>
  </div>
</template>
